#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *lamps = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &lamps[i]);
        }
        qsort(lamps, n, sizeof(int), compare);
        int flag = 1;
        for (int i = 1; i < n; i++) {
            if (lamps[i] - lamps[i - 1] > m) {
                flag = 0;
                break;
            }
        }
        if (flag) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
        free(lamps);
    }
    return 0;
}

