        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let n = input[j * 2][0];
            let m = input[j * 2][1];
            let lamps = input[j * 2 + 1];
